import{_ as i,o as e,c as a,ae as t}from"./chunks/framework.RRduUuAx.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/business/chapter-11.md","filePath":"szu/business/chapter-11.md"}'),o={name:"szu/business/chapter-11.md"};function r(s,l,u,n,h,c){return e(),a("div",null,[...l[0]||(l[0]=[t('<h2 id="第一节、企业文化概述" tabindex="-1">第一节、企业文化概述 <a class="header-anchor" href="#第一节、企业文化概述" aria-label="Permalink to &quot;第一节、企业文化概述&quot;">​</a></h2><ol><li>企业文化的概念 <ul><li>概念：所谓企业文化，是指在一定的社会经济条件下，企业在长期的经营过程中逐渐形成并为全体成员遵循的共同意识、价值观念、职业道德、行为规范和准则的总和。</li><li>企业文化的内容 <ul><li>企业哲学：是指企业在一定社会历史条件下，在生产、经营、管理的活动中所表现出来的世界观和方法论，是企业进行各种活动、处理各种关系、规范职工行为的方法和原则。</li><li>企业价值观：是指企业所拥有的一种积极向上的意识和信念。它是企业文化的深层内容，是一种个性化非常强的文化特征。</li><li>企业制度</li><li>企业道德规范</li><li>企业形象</li></ul></li></ul></li><li>企业文化的层次及其关系 <ul><li>层次：物质层次、制度层次、精神层次文化</li><li>文化层次之间的关系 <ul><li>1.精神层次决定了制度层次和物质层次</li><li>2.制度层次是精神层次和物质层次的中介</li><li>3.物质层次和制度层次是精神层次的体现</li></ul></li></ul></li><li>企业文化的特点 <ul><li>名族性、客观性、独特性、科学性、动态性、约束性、辐射性</li></ul></li><li>企业文化的作用 <ul><li>导向作用、凝聚作用、激励作用、沟通作用、绩效作用</li></ul></li></ol><h2 id="第二节、企业文化管理" tabindex="-1">第二节、企业文化管理 <a class="header-anchor" href="#第二节、企业文化管理" aria-label="Permalink to &quot;第二节、企业文化管理&quot;">​</a></h2><ol><li>企业文化管理的概念<br> 企业的文化管理是指企业的管理者或管理机构，通过计划、组织、人事、领导和控制等工作，对组织所拥有的企业文化资源进行合理的安排和有效的利用，在企业内部形成共同的价值观念、职业道德、行为规范和准则，并根据企业自身的特点选择企业文化的战略和制定管理制度，以实现组织预定目标的过程。</li><li>企业文化管理的影响因素 <ul><li>行业特征、管理者素质、已有的企业文化模式、追求独特模式、形成的长期性</li></ul></li></ol><h2 id="第三节、网络时代企业文化的发展" tabindex="-1">第三节、网络时代企业文化的发展 <a class="header-anchor" href="#第三节、网络时代企业文化的发展" aria-label="Permalink to &quot;第三节、网络时代企业文化的发展&quot;">​</a></h2><ol><li>倡导人本文化<br> 人本文化可以表述为 3P： <ul><li>企业即人（of the people），是指企业是由人组成的集合体，管理应以人为中心。</li><li>企业为人（for the people），企业是为了满足人、满足社会的需求，同时提高员工的生活、工作质量。</li><li>企业靠人（by the people），企业管理的主体是全体员工，企业必须依靠全体员工，充分调动员工的积极性，是其发挥自己的聪明才智。</li></ul></li><li>倡导合作文化</li><li>倡导创新文化</li><li>倡导学习文化</li><li>倡导速度文化</li><li>倡导融合文化</li><li>倡导生态文化</li><li>倡导形象文化</li></ol>',6)])])}const d=i(o,[["render",r]]);export{_ as __pageData,d as default};
